arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // Previously GetEnvironmentVariable("MY_FLAG") returned null for export MY_FLAG="".
        // Now it correctly returns "" for empty vars; only truly unset vars return null.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly set to empty");
        }
    }
}

